### Step 4 — Create the adapter module

**New directory: `/Users/damianpiatkowski/Documents/workspace/inception-engine/src/core/adapters/`**

**New file: `/Users/damianpiatkowski/Documents/workspace/inception-engine/src/core/adapters/index.ts`**

This is the public surface. It re-exports from the two sub-modules below and exports the top-level `compileAdapterActions()` function that `planDeploy()` will call.

```typescript
export { compileMcpServerActions } from "./mcp.ts";
export { compileAgentRuleActions } from "./rules.ts";
import type { McpServerEntry, AgentRuleEntry } from "../../schemas/manifest.ts";
import type { AgentId, ConfigPatchDeployAction, FileWriteDeployAction } from "../../types.ts";
import { compileMcpServerActions } from "./mcp.ts";
import { compileAgentRuleActions } from "./rules.ts";

export type AdapterAction = ConfigPatchDeployAction | FileWriteDeployAction;

export interface AdapterResult {
  actions: AdapterAction[];
  warnings: import("../../types.ts").PlanWarning[];
}

export function compileAdapterActions(
  mcpServers: McpServerEntry[],
  agentRules: AgentRuleEntry[],
  sourceDir: string,
  detectedAgents: AgentId[],
  home: string,
): AdapterResult {
  const actions: AdapterAction[] = [];
  const warnings: import("../../types.ts").PlanWarning[] = [];

  for (const entry of mcpServers) {
    const r = compileMcpServerActions(entry, detectedAgents, home);
    actions.push(...r.actions);
    warnings.push(...r.warnings);
  }

  for (const entry of agentRules) {
    const r = compileAgentRuleActions(entry, sourceDir, detectedAgents, home);
    actions.push(...r.actions);
    warnings.push(...r.warnings);
  }

  return { actions, warnings };
}
```

**New file: `/Users/damianpiatkowski/Documents/workspace/inception-engine/src/core/adapters/mcp.ts`**

```typescript
import path from "node:path";
import { AGENT_REGISTRY_BY_ID } from "../../config/agents.ts";
import { logger } from "../../logger.ts";
import type { McpServerEntry } from "../../schemas/manifest.ts";
import type { AgentId, ConfigPatchDeployAction, PlanWarning } from "../../types.ts";
import { getPlatformKey } from "../resolve.ts";

export interface McpAdapterResult {
  actions: ConfigPatchDeployAction[];
  warnings: PlanWarning[];
}

export function compileMcpServerActions(
  entry: McpServerEntry,
  detectedAgents: AgentId[],
  home: string,
): McpAdapterResult {
  const actions: ConfigPatchDeployAction[] = [];
  const warnings: PlanWarning[] = [];
  const platform = getPlatformKey();

  for (const agentId of entry.agents) {
    if (!detectedAgents.includes(agentId)) continue;
    const agent = AGENT_REGISTRY_BY_ID[agentId];
    if (!agent?.mcpConfigPath) {
      // Not yet implemented — emit a warning and produce no action.
      // This is the intentional stub behavior for the boundary release.
      warnings.push({
        kind: "confidence",
        message: `mcpServers: agent "${agentId}" does not have a documented MCP config path — skipping "${entry.name}"`,
      });
      logger.warn(
        "adapter",
        `mcpServers adapter not yet implemented for agent "${agentId}" (skipping "${entry.name}")`,
      );
      continue;
    }

    const target = path.join(home, ...agent.mcpConfigPath[platform].map(
      (seg) => seg.replace("{home}", home),
    ));

    // The patch shape: { mcpServers: { [name]: config } }
    // This matches the Claude Code and Gemini CLI schema.
    // Agent-specific shape variants can be introduced here when needed.
    const patch: Record<string, unknown> = {
      mcpServers: { [entry.name]: entry.config },
    };

    actions.push({
      kind: "config-patch",
      skill: entry.name,
      agent: agentId,
      target,
      patch,
      confidence: agent.provenance.mcpConfig ?? "provisional",
    });
  }

  return { actions, warnings };
}
```

The path resolution above is intentionally simple — a flat `path.join` over the segments after replacing `{home}`. The existing `resolvePlaceholders()` function in `resolve.ts` handles `{xdg_config}` and `{appdata}` too; we should reuse it. The actual implementation would import `resolvePlaceholders` (currently not exported) or extract it into a shared utility. See the integration notes below.

**New file: `/Users/damianpiatkowski/Documents/workspace/inception-engine/src/core/adapters/rules.ts`**

```typescript
import path from "node:path";
import { AGENT_REGISTRY_BY_ID } from "../../config/agents.ts";
import { logger } from "../../logger.ts";
import type { AgentRuleEntry } from "../../schemas/manifest.ts";
import type { AgentId, FileWriteDeployAction, PlanWarning } from "../../types.ts";
import { getPlatformKey } from "../resolve.ts";

export interface RulesAdapterResult {
  actions: FileWriteDeployAction[];
  warnings: PlanWarning[];
}

export function compileAgentRuleActions(
  entry: AgentRuleEntry,
  sourceDir: string,
  detectedAgents: AgentId[],
  home: string,
): RulesAdapterResult {
  const actions: FileWriteDeployAction[] = [];
  const warnings: PlanWarning[] = [];
  const platform = getPlatformKey();

  for (const agentId of entry.agents) {
    if (!detectedAgents.includes(agentId)) continue;
    const agent = AGENT_REGISTRY_BY_ID[agentId];
    if (!agent?.agentRulesPath) {
      warnings.push({
        kind: "confidence",
        message: `agentRules: agent "${agentId}" does not have a documented rules file path — skipping "${entry.name}"`,
      });
      logger.warn(
        "adapter",
        `agentRules adapter not yet implemented for agent "${agentId}" (skipping "${entry.name}")`,
      );
      continue;
    }

    const source = path.resolve(sourceDir, entry.path);
    const target = path.join(home, ...agent.agentRulesPath[platform].map(
      (seg) => seg.replace("{home}", home),
    ));

    actions.push({
      kind: "file-write",
      skill: entry.name,
      agent: agentId,
      source,
      target,
      confidence: agent.provenance.agentRules ?? "provisional",
    });
  }

  return { actions, warnings };
}
