        assert.match(err.message, /name must contain only/);
        return true;
      });
    } finally {
      rmSync(dir, { recursive: true });
    }
  });

  it("accepts a skill.name with dots, hyphens, and digits (valid-name_1.0)", async () => {
    const dir = makeTmpDir();
    try {
      writeFileSync(
        path.join(dir, "inception.json"),
        JSON.stringify({
          skills: [
            {
              name: "valid-name_1.0",
              path: "skills/s",
              agents: ["claude-code"],
